SELECT cour.course_id as course_id , cour.title as title , u.name as inst_name , substr(cour.start_date,1,10) as start_date , substr(cour.end_date,1,10) as end_date , period_diff(LEFT(REPLACE(cour.end_date, '-',''),6),LEFT(REPLACE(cour.start_date, '-',''),6)) as period_cnt , stu_cour.stu_cnt as stu_cnt , cla.people_limit as people_limit , CASE WHEN cour.start_date > CURDATE() THEN 0 ELSE round((IFNULL(cour_att.출석횟수, 0) / (GREATEST(DATEDIFF(IF(cour.end_date < CURDATE(), cour.end_date, CURDATE()), cour.start_date), 1) * IFNULL(stu_cour.stu_cnt, 1))) * 100, 2) END as att_ratio , cla.class_name as class_name , cour.time_code as time_code , cour.sub_prof as sub_prof , cour.class_id as class_id , sub.name as subInstName , cour.cos_sta_code FROM course cour LEFT JOIN tb_userinfo u ON cour.professor = u.loginID LEFT JOIN course_class cla ON cour.class_id = cla.class_id LEFT JOIN ( SELECT course_id, count(1) as stu_cnt, stu_cou_sta_code FROM student_course WHERE stu_cou_sta_code = 0 GROUP BY 1, 3 ) stu_cour ON stu_cour.course_id = cour.course_id LEFT JOIN ( SELECT COUNT(1) as 출석횟수, course_id FROM course_attendance WHERE att_sta_code = 1 AND DAYOFWEEK(date) BETWEEN 2 AND 6 GROUP BY 2 ) cour_att ON cour_att.course_id = stu_cour.course_id LEFT JOIN tb_userinfo sub ON cour.sub_prof = sub.loginID
(cour.professor = #{loginID} OR cour.sub_prof = #{loginID}) AND cour.course_isDeleted = 0
AND cour.title LIKE CONCAT('%', #{title}, '%')
AND cour.end_date >= #{search_sdate}
AND cour.start_date <= #{search_edate}
AND FIND_IN_SET(cla.class_name, #{course_class})
AND cour.time_code = #{time_code}
AND cour.sub_prof = #{sub_prof}
GROUP BY 1,2,3,4,5,6,7 ORDER BY
cour.title cour.start_date att_ratio cour.start_date
ASC DESC
, cour.course_id DESC LIMIT #{pageIndex}, #{pageSize}

